cat > /home/user/rork-app/expo/__tests__/e2e/ivx-live-qa.mjs << 'TESTEOF'
import { chromium } from 'playwright';

const BASE = 'https://ivxholding.com';
const VIEWPORTS = [
  { name: 'iphone-safari', width: 390, height: 844 },
  { name: 'android-chrome', width: 360, height: 800 },
  { name: 'tablet', width: 768, height: 1024 },
  { name: 'desktop-chrome', width: 1920, height: 1080 },
];

async function run() {
  const browser = await chromium.launch({ headless: true });
  const results = [];

  for (const vp of VIEWPORTS) {
    const ctx = await browser.newContext({ viewport: { width: vp.width, height: vp.height } });
    const page = await ctx.newPage();
    const errors = [];
    const failedRequests = [];

    page.on('console', msg => { if (msg.type() === 'error') errors.push(msg.text()); });
    page.on('requestfailed', req => { failedRequests.push(req.url()); });

    try {
      await page.goto(BASE, { waitUntil: 'networkidle', timeout: 30000 });
      await page.waitForTimeout(2000);

      const scrollWidth = await page.evaluate(() => document.documentElement.scrollWidth);
      const clientWidth = await page.evaluate(() => document.documentElement.clientWidth);
      const hasOverflow = scrollWidth > clientWidth + 2;

      const sections = await page.evaluate(() => {
        const ids = ['properties', 'reels', 'how-it-works', 'trust', 'partners'];
        return ids.filter(id => { const el = document.getElementById(id); return el && el.offsetHeight > 0; });
      });

      const title = await page.title();

      // Test CTA buttons
      const ctaCount = await page.evaluate(() => document.querySelectorAll('button, a[role="button"], .cta, [class*="btn"]').length);

      // Test navigation
      const navLinks = await page.evaluate(() => document.querySelectorAll('nav a, header a, .nav a, [class*="nav"] a').length);

      // Check for black sections (elements with 0 height or no visible content)
      const blackSections = await page.evaluate(() => {
        const sections = document.querySelectorAll('section, div[id]');
        let black = 0;
        sections.forEach(s => {
          const style = window.getComputedStyle(s);
          if (style.backgroundColor === 'rgb(0, 0, 0)' && s.offsetHeight > 100 && s.children.length === 0) black++;
        });
        return black;
      });

      results.push({
        viewport: vp.name,
        width: vp.width,
        height: vp.height,
        title,
        scrollWidth,
        clientWidth,
        hasOverflow,
        sectionsVisible: sections,
        ctaCount,
        navLinks,
        blackSections,
        consoleErrors: errors.length,
        failedRequests: failedRequests.length,
        errorSamples: errors.slice(0, 3),
        failedRequestSamples: failedRequests.slice(0, 3),
        pass: !hasOverflow && sections.length >= 4 && errors.length < 20,
      });
    } catch (err) {
      results.push({ viewport: vp.name, error: err.message, pass: false });
    }
    await ctx.close();
  }

  await browser.close();
  console.log(JSON.stringify(results, null, 2));
}

run().catch(console.error);
TESTEOF

